(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[8035],{6148:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>t});const t={key:"v-15ef718c",path:"/python/data-type/",title:"ประเภทข้อมูล",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:3,title:"ตรวจสอบประเภทของตัวแปร",slug:"ตรวจสอบประเภทของตัวแปร",children:[]},{level:2,title:"การแปลงประเภทตัวแปร",slug:"การแปลงประเภทตัวแปร",children:[{level:3,title:"วิธีการแปลง",slug:"วิธีการแปลง",children:[]}]}],filePathRelative:"python/data-type/README.md",git:{updatedTime:162676698e4,contributors:[]}}},1203:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>p});const t=(0,a(6252).uE)('<h1 id="ประเภทข้อมูล" tabindex="-1"><a class="header-anchor" href="#ประเภทข้อมูล" aria-hidden="true">#</a> ประเภทข้อมูล</h1><p>Data Type หมายความว่า ประเภทของข้อมูลที่จัดเก็บ <br> ซึ่ง Python นั้นก็จะทำการจัดเก็บให้น้องเอง (แหงหล่ะ) แต่น้องก็จำเป็นที่จะต้องรู้ประเภทของมัน เพื่อที่จะทำให้น้องได้ใช้งานตัวแปรได้อย่างถูกต้องนั่นเอง</p><p>ประเภทของค่าตัวแปรนั้น มี <strong>&quot;หลักๆ&quot;</strong> อยู่ 4 ประเภท นั่นคือ</p><table><thead><tr><th>Data Type</th><th>ประเภทข้อมูลที่จัดเก็บ</th><th>ตัวอย่างข้อมูลที่จัดเก็บได้</th></tr></thead><tbody><tr><td>String</td><td>ตัวอักษร</td><td>&quot;kumamon&quot; &quot;1112&quot;</td></tr><tr><td>Boolean</td><td>ค่าจริงหรือเท็จ</td><td>True False</td></tr><tr><td>Float</td><td>ค่าที่มีจุดทศนิยม</td><td>1.00 1.112 -0.999</td></tr><tr><td>Integer</td><td>จำนวนเต็ม</td><td>1 0 -555</td></tr><tr><td>List</td><td>ลิสต์</td><td>[1, 0, -555]</td></tr><tr><td>Dictionary</td><td>ดิกชันแนรี</td><td>[{&#39;a&#39;: &#39;1112&#39;, &#39;b&#39;: 0, &#39;c&#39;: 555}]</td></tr></tbody></table><p>และยังมีประเภทอื่นๆ อีกมากมายที่เราจะขอข้ามไป</p><h3 id="ตรวจสอบประเภทของตัวแปร" tabindex="-1"><a class="header-anchor" href="#ตรวจสอบประเภทของตัวแปร" aria-hidden="true">#</a> ตรวจสอบประเภทของตัวแปร</h3><p>บางครั้งเราอาจจะลืมว่าตัวแปรตอนนี้เก็บข้อมูลประเภทอะไร ก็สามารถเช็คได้โดยการใช้ฟังก์ชัน <code>type()</code> และ Python ก็จะคืนผลลัพธ์ว่าเป็นตัวแปรประเภทใด</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var <span class="token operator">=</span> <span class="token string">&quot;Hello&quot;</span>\n<span class="token builtin">type</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># &lt;class &#39;str&#39;&gt; (เป็นประเภท String)</span>\n\nvar <span class="token operator">=</span> <span class="token string">&quot;1234&quot;</span>\n<span class="token builtin">type</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># &lt;class &#39;str&#39;&gt; (เป็นประเภท String)</span>\n\nvar <span class="token operator">=</span> <span class="token number">1234</span>\n<span class="token builtin">type</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># &lt;class &#39;int&#39;&gt; (เป็นประเภท Integer)</span>\n\nvar <span class="token operator">=</span> <span class="token number">1234.56</span>\n<span class="token builtin">type</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># &lt;class &#39;float&#39;&gt; (เป็นประเภท Float)</span>\n\nvar <span class="token operator">=</span> <span class="token boolean">True</span>\n<span class="token builtin">type</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># &lt;class &#39;bool&#39;&gt; (เป็นประเภท Boolean)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><h2 id="การแปลงประเภทตัวแปร" tabindex="-1"><a class="header-anchor" href="#การแปลงประเภทตัวแปร" aria-hidden="true">#</a> การแปลงประเภทตัวแปร</h2><p>จากในเรื่องเกี่ยวกับการรับ input มานั้น พี่มงได้บอกไว้ว่า</p><p>&quot;input() จะรับมาเป็นประเภท string ทั้งหมดเลย&quot;</p><p>เนื่องจากว่าหากว่าจะเป็นประเภทอื่น ที่ไม่ใช่ string ตัว Data Type ที่เป็น string ก็เก็บได้หมดเลย</p><p>เช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># แล้วพี่มงก็ใส่ค่า &quot;Hello World&quot; เข้ามาเป็น input</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># ผลลัพทืก็จะออกมาเป็น &quot;Hello World&quot;</span>\n\nvar <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># แล้วพี่มงก็ใส่ค่า 1112 เข้ามาเป็น input</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># ผลลัพทืก็จะออกมาเป็น &quot;1112&quot;</span>\n\nvar <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># แล้วพี่มงก็ใส่ค่า True เข้ามาเป็น input</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># ผลลัพทืก็จะออกมาเป็น &quot;True&quot;</span>\n\nvar <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment"># แล้วพี่มงก็ใส่ค่า 11.12 เข้ามาเป็น input</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># ผลลัพทืก็จะออกมาเป็น &quot;11.12&quot;</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>แล้วพี่คะ หนูอยากใช้ integer อ่ะ เพราะอยากให้เอาค่าตัวแปร var1 มาคูณกับ var2</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\nvar2 <span class="token operator">=</span> <span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span>\nvar3 <span class="token operator">=</span> var1 <span class="token operator">*</span> var2\n<span class="token keyword">print</span><span class="token punctuation">(</span>var3<span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>แล้วทำไมมัน error คะ</p><p>พี่มงจะบอกว่า เนื่องจาก input() ที่รับมา ยังเป็นประเภท string อยู่ ไม่ใช่ตัวเลข การเอามาคูณกันจึงเป็นไปไม่ได้ ทำให้เกิด error</p><h3 id="วิธีการแปลง" tabindex="-1"><a class="header-anchor" href="#วิธีการแปลง" aria-hidden="true">#</a> วิธีการแปลง</h3><p>ภายใน python นั้นก็จะมีการแปลงเป็น data type อื่นๆ ดังนี้</p><table><thead><tr><th>Data Type</th><th>วิธีการแปลง</th></tr></thead><tbody><tr><td>String</td><td>string()</td></tr><tr><td>Boolean</td><td>bool()</td></tr><tr><td>Float</td><td>float()</td></tr><tr><td>Integer</td><td>int()</td></tr></tbody></table><p><strong>โดย Python จะพยายามเก็บข้อมูลและแปลงประเภทข้อมูลให้อัตโนมัติ หากมีความจำเป็น</strong></p><p>ตัวอย่างเช่น (การแปลง string ไปเป็น integer)</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var <span class="token operator">=</span> <span class="token string">&quot;1112&quot;</span>\nvar <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># ก็จะได้ผลลัพท์เป็น 1112</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>ตัวอย่างที่ 2 (การเปลี่ยน float ไปเป็น integer)</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var <span class="token operator">=</span> <span class="token number">11.12</span>\nvar <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span>\n<span class="token keyword">print</span><span class="token punctuation">(</span>var<span class="token punctuation">)</span> <span class="token comment"># ก็จะได้ผลลัพท์เป็น 11</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>และการใช้กับ <code>input()</code> ก็สามารถทำแบบนี้ได้เลย</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token builtin">int</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\nvar1 <span class="token operator">=</span> <span class="token builtin">bool</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\nvar1 <span class="token operator">=</span> <span class="token builtin">float</span><span class="token punctuation">(</span><span class="token builtin">input</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>และเนื่องจากมี data type มีมากกว่า 4 ประเภท ตามที่พี่มงได้อธิบายไว้<br> การแปลงประเภทข้อมูลชนิดอื่นๆ จะอยู่ใน lecture ถัดๆไปนะจ๊ะ</p><div class="custom-container warning"><p class="custom-container-title">Challenge</p><p>น้องๆ ลองทดสอบดูครับ ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>var1 <span class="token operator">=</span> <span class="token number">1112</span>\nvar2 <span class="token operator">=</span> <span class="token number">0.1112</span>\nvar3 <span class="token operator">=</span> var1 <span class="token operator">+</span> var2\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>พี่มงจึงได้อยากรู้ว่า <code>var3</code> นั้นได้จัดเก็บเป็นข้อมูลประเภทใด โดยการใช้ <code>type()</code> และก็ได้ผลบอกว่ามันคือประเภท float<br> จึงถามน้องๆว่า var3 ทำไมจึงจัดเก็บไปเป็นประเภท float ครับ?</p></div><hr>',31),p={render:function(n,s){return t}}}}]);